// Simple local test — accepts { "message": "...", "name": "Test User" }
const body = $input.first().json.body;
const message = body?.message || body?.text || '';
const name = body?.name || 'Test User';

if (!message) {
  return [{ json: { error: true, response: 'Send a POST with { "message": "your message" }' } }];
}

return [{
  json: {
    error: false,
    message,
    contactName: name,
    language: /[\u0600-\u06FF]/.test(message) ? 'ar' : 'en'
  }
}];

