// Parse Haiku classification + prepare for main response
const classifyResult = $input.first().json;
const content = classifyResult?.content?.[0]?.text || '{}';

let classification;
try {
  const jsonMatch = content.match(/\{[^}]+\}/);
  classification = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  classification = { intent: 'unknown', confidence: 0, language: 'en', sentiment: 'neutral' };
}

// Get original input data
const orig = $('Parse Input').first().json;

return [{
  json: {
    message: orig.message,
    contactName: orig.contactName,
    language: classification.language || orig.language,
    intent: classification.intent || 'unknown',
    confidence: classification.confidence || 0,
    sentiment: classification.sentiment || 'neutral'
  }
}];

// Build final response
const llmResult = $input.first().json;
const responseText = llmResult?.content?.[0]?.text || 'Sorry, I could not generate a response.';

const classData = $('Parse Classification').first().json;

return [{
  json: {
    response: responseText,
    intent: classData.intent,
    confidence: classData.confidence,
    language: classData.language,
    sentiment: classData.sentiment,
    model: llmResult?.model || 'unknown',
    input_tokens: llmResult?.usage?.input_tokens || 0,
    output_tokens: llmResult?.usage?.output_tokens || 0
  }
}];
